    """
    Safely evaluates a mathematical expression string containing numbers,
    basic arithmetic operators (+, -, *, /, //, %, **), parentheses, and
    whitespace. Does NOT support variables, function calls, or any other
    Python expressions.

    Returns the numeric result as an int or float.
    Raises ValueError for invalid or disallowed expressions.
    """
    import ast
    import operator

    # Allowed operators mapping
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def safe_eval(node):
        if isinstance(node, ast.Expression):
            return safe_eval(node.body)
        elif isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Only numeric constants allowed")
        elif isinstance(node, ast.UnaryOp):
            if type(node.op) in (ast.UAdd, ast.USub):
                return operators[type(node.op)](safe_eval(node.operand))
            raise ValueError("Unsupported unary operator")
        elif isinstance(node, ast.BinOp):
